import microcoapy
import machine

# CoAP server address
COAP_SERVER_ADDRESS = "coap://[your_device_ip]"

# Sensor and actuator values
temp = 25
light = 50

# CoAP server
coap = microcoapy.CoapServer(COAP_SERVER_ADDRESS)

# Sensor resource
@coap.get("/sensors/temp")
def get_temp(request):
    return microcoapy.Message(payload=str(temp))

# Actuator resource
@coap.put("/actuators/light")
def set_light(request):
    global light
    light = int(request.payload)
    return microcoapy.Message(payload="OK")

# Run the CoAP server
coap.run()